class CustomStrategy(SimpleAlgorithm):
    def __algorithm__(self):
        # Diagnostic code to check properties
        feat_keys = []
        try:
            feat_keys = [k for k in dir(self.feat) if not k.startswith('_')]
        except:
            pass

        self_keys = []
        try:
            self_keys = [k for k in dir(self) if not k.startswith('_')]
        except:
            pass

        # Raise an error containing the keys so we can read them from the logs
        raise ValueError(f"DIAGNOSTIC_FEAT: {feat_keys} | DIAGNOSTIC_SELF: {self_keys}")

